using UnityEngine;
using UnityEngine.UI;

/// <summary>
/// Um "nó" (ícone) da Roda de Formas (<see cref="FormWheelUI"/>): representa
/// uma forma desbloqueada (<see cref="FormSwitcher.unlockedForms"/>).
///
/// Estados visuais:
/// - Normal: ícone a cores, sem marcadores.
/// - Forma actual: <see cref="currentMarker"/> activo (ex: anel/contorno).
/// - Seleccionada na roda: <see cref="selectionHighlight"/> activo (destaque
///   do nó sob o cursor/analógico).
/// - Indisponível agora (FormSwitcher.CanSwitchTo == false — ex: no ar,
///   submerso, cooldown): ícone acinzentado (<see cref="unavailableColor"/>)
///   + <see cref="lockIcon"/> activo (cadeado — GDD "feedback de animal
///   bloqueado na roda").
/// </summary>
public class FormWheelNodeUI : MonoBehaviour
{
    [Header("Visual")]
    public Image icon;

    [Tooltip("Cadeado/aviso mostrado sobre o ícone quando a forma não pode ser seleccionada agora (CanSwitchTo == false).")]
    public Image lockIcon;

    [Tooltip("Destaque (anel/glow) activo quando este nó é o seleccionado na roda.")]
    public Image selectionHighlight;

    [Tooltip("Marcador pequeno activo quando este nó representa a forma actualmente equipada.")]
    public Image currentMarker;

    [Header("Cores")]
    public Color availableColor = Color.white;
    public Color unavailableColor = new Color(1f, 1f, 1f, 0.35f);

    /// <summary>Forma representada por este nó (para o FormWheelUI ler ao confirmar/seleccionar).</summary>
    public AnimalFormData Form { get; private set; }

    public void Setup(AnimalFormData form, bool isCurrent, bool isSelected, bool available)
    {
        Form = form;

        if (icon != null)
        {
            icon.sprite = form != null ? form.icon : null;
            icon.color = available ? availableColor : unavailableColor;
        }

        if (lockIcon != null) lockIcon.enabled = !available;
        if (selectionHighlight != null) selectionHighlight.enabled = isSelected;
        if (currentMarker != null) currentMarker.enabled = isCurrent;
    }
}
